// Build Telegram-safe Decision Packet per docs/foundation/DECISION_PACKET_FORMAT.md
// HTML parse_mode: escape dynamic values; static labels keep literal underscores (event_id, human_gate, requires_human).
function escHtml(v) {
  if (v === null || v === undefined) return '';
  const s = Array.isArray(v) ? v.map((x) => escHtml(x)).join('\n') : String(v);
  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}
const d = $input.item.json;
const opts = Array.isArray(d.options) ? d.options : [];
const optionsBlock = opts.map((o) => '  ' + escHtml(o)).join('\n');
const text = [
  '=== TEST ONLY / TEMPLATE VALIDATION ===',
  'No operational action should be taken from this test packet.',
  '',
  'ID: ' + escHtml(d.decision_id),
  'Kind: ' + escHtml(d.kind),
  '',
  'Riferimento evento / provenienza:',
  '  event_id: ' + escHtml(d.event_id),
  '  commit: ' + escHtml(d.source_commit) + ' (' + escHtml(d.source_repo) + ')',
  '  source: ' + escHtml(d.workflow_source),
  '',
  'Risk: ' + escHtml(d.risk) + '          Route: ' + escHtml(d.route) + '       requires_human: ' + escHtml(d.requires_human),
  'Confidence: ' + escHtml(d.confidence) + '    Classifier reason: ' + escHtml(d.classifier_reason),
  '',
  'Contesto:',
  '  ' + escHtml(d.context),
  '',
  'Perché serve decisione:',
  '  ' + escHtml(d.why_decision_needed),
  '',
  'Opzioni:',
  optionsBlock,
  '',
  escHtml(d.recommendation),
  '',
  'Rischio principale (opzione raccomandata):',
  '  ' + escHtml(d.main_risk),
  '',
  'Micro-interazioni eliminate:',
  '  ' + escHtml(d.micro_interactions_eliminated),
  '',
  'Scelta richiesta:',
  '  ' + escHtml(d.requested_reply),
  '',
  'Cosa NON viene fatto senza decisione:',
  '  ' + escHtml(d.what_is_not_done)
].join('\n');
return {
  json: {
    decision_id: d.decision_id,
    decision_packet_text: text,
    test_only: true,
    note: 'Wc Decision Packet text built (HTML-escaped dynamics) — configure Telegram in n8n UI before send'
  }
};

// Read-only inspection of Telegram send result. No secrets persisted.
const resp = $input.item.json;
return {
  json: {
    telegram_send_ok: resp && resp.ok !== undefined ? resp.ok : null,
    message_id: resp && resp.result && resp.result.message_id ? resp.result.message_id : null,
    test_only: true,
    note: 'Wc manual single execution result — sanitize Telegram text before recording'
  }
};
